confidence level refers to how reliable the analysis results are.

sql:
SELECT al.access_id, u.user_id, u.role, u.user_status AS Highest_Status_Level
FROM access_logs al
JOIN users u ON al.user_id = u.user_id;

SELECT trial_id, condition, word, img, trial_notes 
FROM trials 
WHERE condition = 'faceWord_exp';

SELECT 
    (SELECT COUNT(participant_id) FROM participants WHERE consent_form = 1) * 100.0 / 
    (SELECT COUNT(participant_id) FROM participants) AS consent_form_percentage;
